+/// Stream that merges multiple streams in round-robin order.
+pub struct MergedStream<S> {
+    streams: Vec<S>,
+    current: usize,
+}
+
+impl<S> MergedStream<S> {
+    pub fn new(streams: Vec<S>) -> Self {
